import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.Nx1zvZTu.js";const f=JSON.parse('{"title":"Agents & MCP","description":"","frontmatter":{},"headers":[],"relativePath":"mcp/overview.md","filePath":"mcp/overview.md"}'),n={name:"mcp/overview.md"};function i(s,e,c,d,l,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="agents-mcp" tabindex="-1">Agents &amp; MCP <a class="header-anchor" href="#agents-mcp" aria-label="Permalink to &quot;Agents &amp; MCP&quot;">​</a></h1><p>machinable ships an <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP</a> server that lets an AI coding agent drive research with you: author interfaces, run experiments, and ask scientific questions. It stays true to machinable&#39;s code-all-the-way-down approach rather than bolting on an experiment-tracking schema.</p><p>The premise: because experiments, measurements, and even statistical questions are <a href="/guide/inference.html">ordinary interface code</a>, an agent that can read and write that code can run the whole research loop, and machinable&#39;s contracts tell it what to write next.</p><h2 id="the-loop" tabindex="-1">The loop <a class="header-anchor" href="#the-loop" aria-label="Permalink to &quot;The loop&quot;">​</a></h2><blockquote><p><strong>Is SGD faster than Adam on this problem?</strong></p></blockquote><ol><li><strong>Frame</strong> the question as a comparison of operands by a measurable quantity.</li><li><strong>Scaffold</strong> an <a href="/guide/advanced-execution.html#aggregates-and-deferred-collection">aggregate interface</a> that sweeps the experiment. The agent writes it with <code>write_source</code>, and machinable returns any import error so it can self-correct.</li><li><strong>Launch</strong> it. Runs are content-addressed, so this is incremental.</li><li><strong>Ask</strong> an <a href="/guide/inference.html">inference</a> (<code>outperforms</code>, <code>converges_faster</code>, ...). If an operand doesn&#39;t expose the needed <code>&lt;quantity&gt;()</code>, the inference returns a <code>NotImplementedError</code> naming the accessor to write. The agent writes it and re-runs, now a cached no-op for unchanged operands.</li><li><strong>Surface</strong> the verdict as a <a href="/guide/widgets.html">widget</a> for you to validate.</li></ol><p>Every step is content-addressed, searchable, and reproducible, with no tracking layer.</p><h2 id="what-the-server-provides" tabindex="-1">What the server provides <a class="header-anchor" href="#what-the-server-provides" aria-label="Permalink to &quot;What the server provides&quot;">​</a></h2><ul><li><strong>Tools</strong>: authoring (<code>get_module</code>, <code>resolve_config</code>, <code>write_source</code> with import-error surfacing, <code>search_interfaces</code>, <code>launch</code>), inference (<code>outperforms</code>, <code>beats_baseline</code>, <code>ranks</code>, <code>converges_faster</code>, <code>infer</code>, <code>quantity</code>), and widget verification (<code>read_widget_result</code>).</li><li><strong>Resources</strong>: the context the agent writes against, attached without tool calls: <code>guide://authoring</code>, <code>inferences://catalog</code>, <code>examples://{name}</code>, <code>module://{module}</code>, <code>widget-sdk://docs</code>.</li><li><strong>Prompts</strong>: canned workflows (<code>investigate</code>, <code>scaffold-aggregate</code>, <code>add-inference</code>, <code>scaffold-widget</code>).</li></ul><h2 id="read-on" tabindex="-1">Read on <a class="header-anchor" href="#read-on" aria-label="Permalink to &quot;Read on&quot;">​</a></h2><ul><li><a href="./setup.html">Setup</a>: install and launch the server, connect a client.</li><li><a href="./workflow.html">The research workflow</a>: the <code>investigate</code> loop in detail.</li><li><a href="./authoring.html">Authoring for agents</a>: the tools, resources, and prompts.</li><li><a href="./reference-inferences.html">Reference inferences</a>: the inferences that ship with it.</li></ul><p>Why inferences instead of a metrics schema is covered in <a href="/design/inference.html">Design notes → Inference design</a>.</p>',12)])])}const p=t(n,[["render",i]]);export{f as __pageData,p as default};
